head.script:
//현재일자 
scwin.vCurDate = $c.date.getServerDateTime();
scwin.vQryStDt = scwin.vCurDate.substr(0, 6) + "01";
scwin.vQryEndDt = scwin.vCurDate.substr(0, 6) + $c.date.getLastDateOfMonth(scwin.vCurDate.substr(0, 6));

scwin.onpageload = function () {
    const codeOptions = [
         { grpCd : "SD070", compID : "acb_taxnClsCd", opt:{"range":"1"} } // 부가세구분
        ,{ grpCd : "FM018", compID : "gr_dnTrustTaxInvoice:reqPayMthdCd", opt:{"range":"1"} } // 지급방법 
    ];
    $c.data.setCommonCode(codeOptions);

    ds_condition.insertRow();
    ds_condition.setRowPosition(0);

    gr_dnTrustTaxInvoice.setColumnStyle("button", "color", "blue");
    gr_dnTrustTaxInvoice.setColumnStyle("button", "text-decoration", "underline");
    gr_dnTrustTaxInvoice.setColumnStyle("button", "cursor", "pointer");
};

scwin.onUdcCompleted = function () {
    ed_qryConDtFm.setValue(scwin.vQryStDt);
    ed_qryConDtTo.setValue(scwin.vQryEndDt);

    rd_acctGubun.setValue("0");
    ed_homeClntNo.focus();	
};

scwin.ondataload = function () {
    acb_qryDtConKnd.setValue("CERTI");
    acb_taxnClsCd.setValue("03");   //rd_taxnClsCd.Index = 2; 
};

//-------------------------------------------------------------------------
// Function
//-------------------------------------------------------------------------
// 거래명세서 조회
scwin.f_Retrieve = async function () {
    // 조회시작일자가 더 클경우 체크
    if (!await $c.gus.cfIsAfterDate(ed_qryConDtFm.getValue(), ed_qryConDtTo.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        return;
    }

    let e = await $c.sbm.execute(sbm_searchCertiList);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
        scwin.sbm_searchCertiList_submitdone(e);
    }
};

// 팝업창 처리
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    var rtnList  = new Array();  // 공통POP-UP -> 요청화면

    switch (disGubun) {
        case 1: // 소속거래처
            udc_homeClntNo.setSelectId("retrieveSubsidaryClntListJa"); 
            rtnList = await udc_homeClntNo.cfCommonPopUpAsync(
                                                                  ''   	                            // XML상의 SELECT ID
                                                                , pCode								// 화면에서의 ??? Code Element의	Value
                                                                , pName								// 화면에서의 ??? Name Element의	Value
                                                                , pClose							// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                                                , '5'								// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                                                , null								// Title순서
                                                                , '150,170'  		    			// 보여주는 각 컬럼들의 폭
                                                                , null								// 컬럼중에서 숨기는	컬럼 지정
                                                                , null								// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                                                , null								// POP-UP뛰을때 원도우의	사용자 정의	폭
                                                                , null								// POP-UP뛰을때 우도우의	사용자 정의	높이
                                                                , null								// 윈도우 위치 Y좌표
                                                                , null								// 윈도우 위치 X좌표
                                                                , null								// 중복체크여부	("F")
                                                                , pAllSearch						// 전체검색허용여부	("F")
                                                                , "소속거래처,거래처코드,거래처명"	  // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                                            );
        if (rtnList != null) {
            $c.gus.cfSetReturnValue(rtnList, ed_homeClntNo, ed_homeClntNm);
        }
        break;
        case 2:
            //미지급거래처
            udc_acctClntNo.setSelectId("retrieveSubsidaryClntListJa"); 
            rtnList = await udc_acctClntNo.cfCommonPopUpAsync(
                                                                  ''   	                            // XML상의 SELECT ID
                                                                , pCode								// 화면에서의 ??? Code Element의	Value
                                                                , pName								// 화면에서의 ??? Name Element의	Value
                                                                , pClose							// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                                                , '5'								// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                                                , null								// Title순서
                                                                , '150,170'  		    			// 보여주는 각 컬럼들의 폭
                                                                , null								// 컬럼중에서 숨기는	컬럼 지정
                                                                , null								// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                                                , null								// POP-UP뛰을때 원도우의	사용자 정의	폭
                                                                , null								// POP-UP뛰을때 우도우의	사용자 정의	높이
                                                                , null								// 윈도우 위치 Y좌표
                                                                , null								// 윈도우 위치 X좌표
                                                                , null								// 중복체크여부	("F")
                                                                , pAllSearch						// 전체검색허용여부	("F")
                                                                , "미지급거래처,거래처코드,거래처명"  // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                                            );
            if (rtnList != null) {
                $c.gus.cfSetReturnValue(rtnList, ed_acctClntNo, ed_acctClntNm);
                //rd_acctGubun.codeValue = 1;          
            }
        break;
        default:
        break;
    }
};

// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);


    if (isCode == null || isCode == true) {
        // inObj가 코드 필드일 경우 팝업
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    } else {
        // inObj가 코드명 필드일 경우 팝업
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

// 전표일자, 공급일자 일자일괄적용
scwin.f_adaptSlipDt = function () {
    var chkCnt = 0;
    var stPos = ds_dnTrustTaxInvoice.getRowPosition();

    var slipDt = ds_dnTrustTaxInvoice.getCellData(stPos, "slipDt");
    var spplyDt = ds_dnTrustTaxInvoice.getCellData(stPos, "spplyDt");
    var reqDt = ds_dnTrustTaxInvoice.getCellData(stPos, "reqDt");
    var postDt = ds_dnTrustTaxInvoice.getCellData(stPos, "postDt");

    for (var i = 0; i < ds_dnTrustTaxInvoice.getRowCount(); i++) {
        if(ds_dnTrustTaxInvoice.getCellData(i, "choice") == "T") {
            ds_dnTrustTaxInvoice.setCellData(i, "slipDt", slipDt);
            ds_dnTrustTaxInvoice.setCellData(i, "spplyDt", spplyDt);
            ds_dnTrustTaxInvoice.setCellData(i, "reqDt", reqDt);
            ds_dnTrustTaxInvoice.setCellData(i, "postDt", postDt);
            chkCnt++;
        }
    }
    if (chkCnt == 0) {
        $c.win.alert("선택된 행이 없습니다. 일괄적용할 행들을 선택해 주십시오.");
        return false;
    }
};

// 전도금 미지급금 계정일괄적용 20170807
scwin.f_adaptAcctGubun = function () {
    var chkCnt = 0;

    var gubun = rd_acctGubun.getValue();       // gubun 0:전도금 1:미지급금
    var acctClntNo = ed_acctClntNo.getValue(); // 미지급거래처

    if (gubun == "1" && acctClntNo == "") {
        $c.win.alert("미지급금인 경우 미지급거래처를 입력하세요.");
        return;
    }
    for (var i = 0; i < ds_dnTrustTaxInvoice.getRowCount(); i++) {
        if (ds_dnTrustTaxInvoice.getCellData(i, "choice") == "T") {
            ds_dnTrustTaxInvoice.setCellData(i, "acctGubun", gubun);
            if (gubun == "1") {
                ds_dnTrustTaxInvoice.setCellData(i, "bilgClntNo", acctClntNo);
            } else {
                ds_dnTrustTaxInvoice.setCellData(i, "bilgClntNo", "280161"); // 20170822 성원영대리님 요청(전도금-일반계정의 귀속부서만 00915)
            }
            chkCnt++;
        }
    }

    if (chkCnt == 0) {
        $c.win.alert("선택된 행이 없습니다. 일괄적용할 행들을 선택해 주십시오.");
        return;
    }
};

// 검색영역 Field Clear함.
scwin.f_InitObjects = function () {
    $c.gus.cfInitObjects(tb_mainData);
    scwin.f_SetDefaultData();
};

// 조회조기 필드 Clear
scwin.f_FieldClear = function () {
    ed_qryConDtFm.setValue(scwin.vQryStDt);
    ed_qryConDtTo.setValue(scwin.vQryEndDt);

    // CERTI^거래명세서일자,SPPLY^세금계산서일자,POST^회계일자
    acb_qryDtConKnd.setValue("CERTI");
    acb_taxnClsCd.setValue("03");

    ed_homeClntNo.setValue(""); // 거래처번호
    ed_homeClntNm.setValue("");	// 거래처명
};

// 일괄생성
scwin.f_Save = async function () {
    var chkCreateCnt = 0;
    for (var i = 0; i < ds_dnTrustTaxInvoice.getRowCount(); i++) {
        if (ds_dnTrustTaxInvoice.getCellData(i, "choice") == "T") {
            if (ds_dnTrustTaxInvoice.getCellData(i, "slipNo") == null || ds_dnTrustTaxInvoice.getCellData(i, "slipNo") == "") {
                chkCreateCnt++;
                scwin.f_SetDataSet(chkCreateCnt, i);
            } else {
                $c.win.alert((i+1) + "번째 행은 이미 전표가 생성된 건입니다. 다시 확인해주십시오.");
                return false;
            }            	
        }
    }

    if (chkCreateCnt == 0) {
        $c.win.alert("선택된 행이 없습니다. 일괄생성할 행들을 선택해 주십시오.");
        return false;
    } else {
        let e = await $c.sbm.execute(sbm_save);
        if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
            scwin.sbm_save_submitdone(e);
        }
    }
};

// Save or Del DataSet Setting
scwin.f_SetDataSet = function (chkCreateCnt, row) {
    ds_sellingEvidenceSave.removeAll();
    var rowIndex = ds_sellingEvidenceSave.insertRow();

    ds_sellingEvidenceSave.setCellData(rowIndex, "choice", "T");
    ds_sellingEvidenceSave.setCellData(rowIndex, "slipDt", ds_dnTrustTaxInvoice.getCellData(row, "slipDt"));
    ds_sellingEvidenceSave.setCellData(rowIndex, "slipNo", ds_dnTrustTaxInvoice.getCellData(row, "slipNo"));
    ds_sellingEvidenceSave.setCellData(rowIndex, "summary", ds_dnTrustTaxInvoice.getCellData(row, "summary"));              
    ds_sellingEvidenceSave.setCellData(rowIndex, "spplyDt", ds_dnTrustTaxInvoice.getCellData(row, "spplyDt"));
    ds_sellingEvidenceSave.setCellData(rowIndex, "clntNo", ds_dnTrustTaxInvoice.getCellData(row, "clntNo"));
    ds_sellingEvidenceSave.setCellData(rowIndex, "crn"   , ds_dnTrustTaxInvoice.getCellData(row, "crn"));
    ds_sellingEvidenceSave.setCellData(rowIndex, "postDt", ds_dnTrustTaxInvoice.getCellData(row, "postDt"));             
    ds_sellingEvidenceSave.setCellData(rowIndex, "collMoneyAcctDeptCd", ds_dnTrustTaxInvoice.getCellData(row, "collMoneyAcctDeptCd"));
    ds_sellingEvidenceSave.setCellData(rowIndex, "bilgLodeptCd", ds_dnTrustTaxInvoice.getCellData(row, "bilgLodeptCd"));
    ds_sellingEvidenceSave.setCellData(rowIndex, "acctDeptCd", ds_dnTrustTaxInvoice.getCellData(row, "acctDeptCd"));
    ds_sellingEvidenceSave.setCellData(rowIndex, "bilgClntNo", ds_dnTrustTaxInvoice.getCellData(row, "bilgClntNo"));
    ds_sellingEvidenceSave.setCellData(rowIndex, "bilgClntNm", ds_dnTrustTaxInvoice.getCellData(row, "bilgClntNm"));

    ds_sellingEvidenceSave.setCellData(rowIndex, "crcCd", "KRW");
    ds_sellingEvidenceSave.setCellData(rowIndex, "receptClsCd", "01");     // 영수
    ds_sellingEvidenceSave.setCellData(rowIndex, "evidRglClsCd", "01");     //세금계산서 상태 : 01 '정상', 02 '적자', 99 '삭제'
    ds_sellingEvidenceSave.setCellData(rowIndex, "certiNo", ds_dnTrustTaxInvoice.getCellData(row, "certiNo"));      //거래명세서번호
    ds_sellingEvidenceSave.setCellData(rowIndex, "certiCnt", "1");      //거래명세서건수
    ds_sellingEvidenceSave.setCellData(rowIndex, "bilgAmt", "0");
    ds_sellingEvidenceSave.setCellData(rowIndex, "bilgAmtFcrc", "0");
    ds_sellingEvidenceSave.setCellData(rowIndex, "fcrcBilgAmt", "0");
    ds_sellingEvidenceSave.setCellData(rowIndex, "spplyAmt", ds_dnTrustTaxInvoice.getCellData(row, "spplyAmt"));
    ds_sellingEvidenceSave.setCellData(rowIndex, "vatAmt", ds_dnTrustTaxInvoice.getCellData(row, "vatAmt"));
    ds_sellingEvidenceSave.setCellData(rowIndex, "fmlaPatternCd", "K5");
    ds_sellingEvidenceSave.setCellData(rowIndex, "fmlaClsCd", "01");
    ds_sellingEvidenceSave.setCellData(rowIndex, "dcsnClsCd", "3");
    ds_sellingEvidenceSave.setCellData(rowIndex, "taxnClsCd", "03");    // 부가세 구분 : 기타
    ds_sellingEvidenceSave.setCellData(rowIndex, "slipKndCd", "K05");

    ds_sellingEvidenceSave.setCellData(rowIndex, "bilgCrn", ds_dnTrustTaxInvoice.getCellData(row, "bilgCrn"));  // 지급처 사업자번호
    ds_sellingEvidenceSave.setCellData(rowIndex, "reqPayMthdCd", ds_dnTrustTaxInvoice.getCellData(row, "reqPayMthdCd")); //지급방법
    ds_sellingEvidenceSave.setCellData(rowIndex, "reqDt", ds_dnTrustTaxInvoice.getCellData(row, "reqDt")); //지급일자
    ds_sellingEvidenceSave.setCellData(rowIndex, "sellDrAcctCd", ds_dnTrustTaxInvoice.getCellData(row, "sellDrAcctCd"));

    ds_sellingEvidenceSave.setCellData(rowIndex, "acctGubun", ds_dnTrustTaxInvoice.getCellData(row, "acctGubun"));
};

//-------------------------------------------------------------------------
// 공통팝업호출 callBack
//-------------------------------------------------------------------------
// 계약거래처

//-------------------------------------------------------------------------
// Sbm submitdone
//-------------------------------------------------------------------------
scwin.sbm_searchCertiList_submitdone = async function (e) {
    totalRows.setValue(ds_dnTrustTaxInvoice.getRowCount())

    if (ds_dnTrustTaxInvoice.getRowCount() == 0) {
        if ($c.gus.cfCheckCreateFlag() == true) {
            $c.gus.cfTurnCreateFlag(false);
        } else {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        }
    } else {
        ica_slipCloseYm.setValue(ds_dnTrustTaxInvoice.getCellData(0, "slipCloseYm"));  // 회계마감월
        ica_taxCloseYm.setValue(ds_dnTrustTaxInvoice.getCellData(0, "taxCloseYm"));    // 세무마감월
    }
};

scwin.sbm_save_submitdone = async function (e) {
    if (await $c.gus.cfAlertMsg(MSG_CM_INF_001)) { // 성공적으로 저장하였습니다
        scwin.f_Retrieve();	
    } 
};

//-------------------------------------------------------------------------
// Event onClick
//-------------------------------------------------------------------------
// 조회 버튼 클릭 이벤트 
scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();
};

// 초기화 버튼 클릭 이벤트 
scwin.btn_fieldClear_onclick = function (e) {
    scwin.f_FieldClear();
};

// 일괄생성 버튼 클릭 이벤트
scwin.btn_Save_onclick = function (e) {
    scwin.f_Save();
};

// 소속거래처 찾기 버튼 클릭 이벤트
scwin.udc_homeClntNo_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_homeClntNo.getValue(), ed_homeClntNm.getValue(), 'F', 'F');
};

// 미지급거래처 찾기 버튼 클릭 이벤트
scwin.udc_acctClntNo_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(2, ed_acctClntNo.getValue(), ed_acctClntNm.getValue(), 'F', 'F');
};

// 일자일괄적용 버튼 클릭 이벤트
scwin.btn_adaptSlipDt_onclick = function (e) {
    scwin.f_adaptSlipDt();
};

// 계정일괄적용 버튼 클릭 이벤트
scwin.btn_adaptAcctGubun_onclick = function (e) {
    scwin.f_adaptAcctGubun();
};

//-------------------------------------------------------------------------
// Event onchange
//-------------------------------------------------------------------------
scwin.acb_qryDtConKnd_onchange = function (info) {
    ds_dnTrustTaxInvoice.removeAll();
};

//-------------------------------------------------------------------------
// Event onblur
//-------------------------------------------------------------------------
// 소속거래처 Onbluer(onKillFocus) 이벤트 발생시
scwin.udc_homeClntNo_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_homeClntNo, ed_homeClntNm, 1);
};

// 미지급거채러 Onbluer(onKillFocus) 이벤트 발생시
scwin.udc_acctClntNo_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_acctClntNo, ed_acctClntNm, 2);
};

//-------------------------------------------------------------------------
// Event onviewchange
//-------------------------------------------------------------------------
// 소속거래처 onviewchange 이벤트 발생시
scwin.udc_homeClntNo_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_homeClntNm, ed_homeClntNo, 1, false);
};

// 미지급거래처 onviewchange 이벤트 발생시
scwin.udc_acctClntNo_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_acctClntNm, ed_acctClntNo, 2, false);
};

scwin.rd_acctGubun_onviewchange = function (info) {
    // gubun 0:전도금 1:미지급금
    var gubun = rd_acctGubun.getValue();             
    if (gubun == "0") { // 0전도금
        ed_acctClntNo.setValue("");
        ed_acctClntNm.setValue("");
    }
};

//-------------------------------------------------------------------------
// DataSet 이벤트
//-------------------------------------------------------------------------

//-------------------------------------------------------------------------
// 그리드 이벤트
//-------------------------------------------------------------------------
scwin.gr_dnTrustTaxInvoice_onheaderclick = function (headerId) {
    var i = 0;
    var bCheck = gr_dnTrustTaxInvoice.getHeaderValue("column1");  // 체크 여부

    if (headerId == "column1")  {
        if (bCheck == true) {
            for (var i = 0; i < ds_dnTrustTaxInvoice.getTotalRow(); i++) {
                ds_dnTrustTaxInvoice.setCellData(i, "choice", "T");
            }
        } else {
            for (var i = 0; i < ds_dnTrustTaxInvoice.getTotalRow(); i++) {
                ds_dnTrustTaxInvoice.setCellData(i, "choice", "F");
            }
        }
    }
};

scwin.gr_dnTrustTaxInvoice_oncellclick = async function (rowIndex, columnIndex, columnId) {
     if(columnId == "button" && rowIndex >= 0){

        ds_dnTrustTaxInvoice.setCellData(rowIndex, "choice", "T");

        var valueObject = new Object();

        valueObject.pchsClntNo           = ds_dnTrustTaxInvoice.getCellData(rowIndex, "bilgClntNo" );
        valueObject.certiNo              = ds_dnTrustTaxInvoice.getCellData(rowIndex, "certiNo"    );
        valueObject.homeClntNo           = ds_dnTrustTaxInvoice.getCellData(rowIndex, "homeClntNo" );    
        valueObject.acctGubun          	 = ds_dnTrustTaxInvoice.getCellData(rowIndex, "acctGubun"  );    
        valueObject.oldBilgClntNo        = ds_dnTrustTaxInvoice.getCellData(rowIndex, "oldBilgClntNo" );

        var opts = {
            id : "smpPop"	
            , popupName : "대납전표개별생성"
            , modal : true
            , type : "browserPopup"
            , width : 840
            , height : 440
            , title : "대납전표개별생성"
        };

        $c.win.openPopup("/ui/ja/dnja/consignmgnt/dnja_210_03_02p.xml", opts, valueObject); 

        let e = await $c.sbm.execute(sbm_searchCertiList);
        if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
            scwin.sbm_searchCertiList_submitdone(e);
        }
    }
};

//-------------------------------------------------------------------------
// Formatter
//-------------------------------------------------------------------------
scwin.f_gr_dnTrustTaxInvoice_customFormatter = function(data, formattedData, rowIndex, colIndex) {
    let columnId =  $c.util.getComponent(this.id).getColumnID(colIndex);
    let val = data, color = "black";

    var slipNo = ds_dnTrustTaxInvoice.getCellData(rowIndex, "slipNo");

    if (columnId == "acctGubun") {
        if (slipNo == "") {
            if (data == 0) {
                val = "전도금";
            } else {
                val = "미지급금";
            }
        } else {
            val = "";
        }
    }

    return val;
};

scwin.gr_dnTrustTaxInvoice_onbeforecolumnmove = function (info) {
    const validArr = ["choice", "button", "slipNo"];
    const startColumnID = info.startColumnID;
    const endColumnID = info.endColumnID;
    if($.inArray(startColumnID, validArr) > -1) {
        return false;

    }
    if($.inArray(endColumnID, validArr) > -1) {
         return false;
    }
};
